mapper.select:
SELECT id, author_id AS authorId, category_id AS categoryId, title, content, tags, likes, favorites, comments, views, is_top AS isTop, is_essence AS isEssence, status, create_time AS createTime, update_time AS updateTime FROM post WHERE status = 0 AND category_id = #{categoryId}
AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))
AND IFNULL(is_essence, 0) = 1
ORDER BY IFNULL(is_top, 0) DESC, IFNULL(is_essence, 0) DESC, create_time DESC LIMIT #{offset}, #{limit}

mapper.update:
UPDATE post
SET title = #{title}, content = #{content}, tags = #{tags}, update_time = #{updateTime}
WHERE id = #{id}

UPDATE post
SET likes = GREATEST(0, IFNULL(likes, 0) - 1)
WHERE id = #{id}

mapper.select:
SELECT COUNT(*)
FROM `like` l
WHERE l.user_id = #{userId}
  AND l.target_type = #{targetType}
  AND l.action = 'LIKE'
